fn cmd_task(
    db: &shell::Db,
    command: TaskCommands,
    _skip_confirm: bool,
    _is_tty: bool,
) -> Result<()> {
    match command {
        TaskCommands::Add {
            title,
            column,
            desc,
            priority,
        } => {
